import { useState, useEffect } from "react";

function App() {
  const [file, setFile] = useState(null);
  const [preview, setPreview] = useState(null);
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [zoom, setZoom] = useState(false);
  const [animatedScore, setAnimatedScore] = useState(0);
  const [downloading, setDownloading] = useState(false);
  const [darkMode, setDarkMode] = useState(true);

  const claimId = `CLM-${Date.now()}`;

  // Fraud Score Animation
  useEffect(() => {
    if (result) {
      let start = 0;
      const end = result.fraud_confidence_score || 0;
      const duration = 1200;
      const stepTime = 20;
      const step = (end - start) / (duration / stepTime);

      const interval = setInterval(() => {
        start += step;
        if (start >= end) {
          start = end;
          clearInterval(interval);
        }
        setAnimatedScore(Math.round(start));
      }, stepTime);
    }
  }, [result]);

  const riskLevel = (score) => {
    if (score <= 40) return "Low Risk";
    if (score <= 75) return "Medium Risk";
    return "High Risk";
  };

  const gaugeColor = (score) =>
    score <= 50 ? "#00ff9c" : score <= 80 ? "#ffea00" : "#ff3d00";

  const verdictColor = (verdict) => {
    if (!verdict) return "#aaa";
    if (verdict.toLowerCase() === "fraud") return "#ff3d00";
    if (verdict.toLowerCase() === "suspicious") return "#ffea00";
    return "#00ff9c";
  };

  // File Handling
  const handleFileChange = (e) => {
    setError(null);
    const selected = e.target.files[0];
    if (!selected) return;
    setFile(selected);
    setPreview(URL.createObjectURL(selected));
    setResult(null);
    setAnimatedScore(0);
  };

  const handleUpload = async () => {
    if (!file) return setError("Please select an image first.");
    const formData = new FormData();
    formData.append("file", file);
    setLoading(true);
    setResult(null);

    try {
      const response = await fetch("http://127.0.0.1:8000/api/audit", {
        method: "POST",
        body: formData,
      });
      if (!response.ok) throw new Error("Server error");
      const data = await response.json();
      setResult(data);
    } catch (err) {
      setError(err.message || "Something went wrong!");
    }
    setLoading(false);
  };

  const handleReset = () => {
    setFile(null);
    setPreview(null);
    setResult(null);
    setError(null);
    setZoom(false);
    setAnimatedScore(0);
    setDownloading(false);
  };

  // Download Report
  const downloadReport = () => {
    if (!result) return;
    setDownloading(true);

    const htmlContent = `
      <html>
      <head>
        <title>Audit Report - ${claimId}</title>
        <style>
          body { font-family: Arial, sans-serif; padding: 20px; background: ${
            darkMode ? "#111" : "#f9f9f9"
          }; color: ${darkMode ? "#fff" : "#111"}; }
          h1,h2,h3 { color: ${darkMode ? "#00ff9c" : "#2d3436"}; }
          .meta { font-size:14px; color:${darkMode ? "#aaa" : "#555"}; margin-bottom:20px; }
          .stats { display:flex; flex-wrap:wrap; gap:20px; margin-bottom:30px; }
          .statBox { flex:1 1 180px; background:${
            darkMode ? "rgba(255,255,255,0.05)" : "#fff"
          }; padding:15px; border-radius:8px; text-align:center; ${
      darkMode ? "" : "box-shadow:0 3px 10px rgba(0,0,0,0.1);"
    }}
          ul { padding-left:20px; }
          pre { background:${darkMode ? "rgba(255,255,255,0.05)" : "#f1f3f6"}; padding:10px; border-radius:6px; overflow-x:auto; }
          .green { color:#00ff9c; font-weight:bold; }
          .yellow { color:#ffea00; font-weight:bold; }
          .red { color:#ff3d00; font-weight:bold; }
        </style>
      </head>
      <body>
        <h1>ClaimPilot AI Audit Report</h1>
        <p class="meta">Claim ID: <strong>${claimId}</strong><br/>Date: ${new Date().toLocaleString()}</p>
        <div class="stats">
          <div class="statBox"><h3>Total Estimate</h3><p>PKR ${result.total_estimate_pkr}</p></div>
          <div class="statBox"><h3>Fraud Score</h3>
            <p class="${
              result.fraud_confidence_score <= 50
                ? "green"
                : result.fraud_confidence_score <= 80
                ? "yellow"
                : "red"
            }">${result.fraud_confidence_score}%</p>
          </div>
          <div class="statBox"><h3>Verdict</h3>
            <p class="${
              result.verdict.toLowerCase() === "fraud"
                ? "red"
                : result.verdict.toLowerCase() === "suspicious"
                ? "yellow"
                : "green"
            }">${result.verdict}</p>
          </div>
          <div class="statBox"><h3>Damaged Parts</h3><p>${result.damaged_parts?.length || 0}</p></div>
        </div>
        <h2>Fraud Analysis</h2><p>${result.fraud_analysis || "No fraud detected."}</p>
        <h2>Damaged Parts</h2>${
          result.damaged_parts?.length
            ? `<ul>${result.damaged_parts.map((p) => `<li>${p}</li>`).join("")}</ul>`
            : "<p>No parts detected.</p>"
        }
        <h2>Itemized Costs</h2>
        <pre>${JSON.stringify(result.itemized_costs, null, 2)}</pre>
        <h2>AI Confidence Explanation</h2>
        <p>Score calculated using anomaly detection, metadata consistency checks, and cost deviation models.</p>
      </body>
      </html>
    `;

    const blob = new Blob([htmlContent], { type: "text/html" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `audit_report_${claimId}.html`;
    a.click();
    URL.revokeObjectURL(url);
    setTimeout(() => setDownloading(false), 800);
  };

  // -------------------- Themes --------------------
  const darkTheme = {
    page: {
      minHeight: "100vh",
      background: "linear-gradient(135deg,#0f0c29,#302b63,#24243e)",
      fontFamily: "Poppins, sans-serif",
      padding: 30,
      color: "#fff",
    },
    container: { maxWidth: 900, margin: "auto", padding: "0 15px" },
    header: { textAlign: "center", marginBottom: 50 },
    logo: {
      fontSize: 42,
      fontWeight: 800,
      background: "linear-gradient(90deg,#00ff9c,#00f0ff)",
      WebkitBackgroundClip: "text",
      color: "transparent",
    },
    tagline: { marginTop: 10, color: "#aaa", fontSize: 16 },
    uploadCard: {
      background: "rgba(255,255,255,0.05)",
      padding: 30,
      borderRadius: 18,
      border: "1px solid rgba(0,255,156,0.3)",
      backdropFilter: "blur(15px)",
      boxShadow: "0 10px 30px rgba(0,0,0,0.2)",
      marginBottom: 40,
      transition: "transform 0.3s ease",
    },
    uploadLabel: {
      display: "block",
      border: "2px dashed #00ff9c",
      padding: 25,
      borderRadius: 15,
      textAlign: "center",
      fontWeight: 600,
      cursor: "pointer",
      marginBottom: 25,
      transition: "0.3s all",
      color: "#fff",
    },
    preview: {
      width: "100%",
      maxHeight: 320,
      borderRadius: 15,
      marginBottom: 15,
      cursor: "zoom-in",
      objectFit: "cover",
      boxShadow: "0 8px 25px rgba(0,255,156,0.3)",
      transition: "all 0.3s ease",
    },
    previewZoom: {
      width: "100%",
      maxHeight: 600,
      borderRadius: 15,
      marginBottom: 15,
      cursor: "zoom-out",
      objectFit: "contain",
      boxShadow: "0 0 40px rgba(0,255,156,0.5)",
      transition: "all 0.3s ease",
    },
    buttonRow: { display: "flex", gap: 15, justifyContent: "center", flexWrap: "wrap" },
    primaryBtn: {
      padding: "12px 28px",
      background: "linear-gradient(90deg,#00ff9c,#00f0ff)",
      borderRadius: 12,
      border: "none",
      fontWeight: 600,
      cursor: "pointer",
      color: "#111",
      boxShadow: "0 5px 15px rgba(0,255,156,0.4)",
      transition: "0.3s all",
    },
    resetBtn: {
      padding: "12px 28px",
      background: "#ff3d00",
      borderRadius: 12,
      border: "none",
      fontWeight: 600,
      cursor: "pointer",
      color: "#fff",
      boxShadow: "0 5px 15px rgba(255,61,0,0.4)",
      transition: "0.3s all",
    },
    disabledBtn: {
      padding: "12px 28px",
      background: "#555",
      borderRadius: 12,
      border: "none",
      color: "#ccc",
    },
    resultCard: {
      background: "rgba(255,255,255,0.07)",
      borderRadius: 20,
      padding: 35,
      boxShadow: "0 10px 40px rgba(0,0,0,0.25)",
      backdropFilter: "blur(20px)",
      marginTop: 20,
      transition: "transform 0.3s ease",
    },
    meta: { fontSize: 13, color: "rgba(255,255,255,0.6)" },
    stats: { display: "flex", flexWrap: "wrap", gap: 15, margin: "30px 0", justifyContent: "center" },
    statBox: {
      flex: "1 1 200px",
      padding: 20,
      borderRadius: 15,
      background: "rgba(255,255,255,0.05)",
      textAlign: "center",
      boxShadow: "0 8px 20px rgba(0,255,156,0.2)",
      transition: "0.3s transform",
      cursor: "default",
    },
    gauge: { width: 90, height: 90 },
    gaugeText: { fontSize: 10, fontWeight: 700, fill: "#fff", textAnchor: "middle" },
    progressBar: { height: 14, background: "#111", borderRadius: 12, overflow: "hidden", marginBottom: 20 },
    progressFill: { height: "100%", background: "linear-gradient(90deg,#00ff9c,#ffea00,#ff3d00)", transition: "width 1s ease" },
    partItem: { display: "flex", justifyContent: "space-between", padding: "10px 0", borderBottom: "1px solid rgba(255,255,255,0.1)" },
    severity: { background: "#ff3d0033", color: "#ff3d00", padding: "3px 10px", borderRadius: 8, fontWeight: 600 },
    pre: { background: "rgba(255,255,255,0.05)", padding: 20, borderRadius: 12, overflowX: "auto", color: "#fff" },
    downloadBtn: {
      marginTop: 25,
      padding: "12px 28px",
      background: "linear-gradient(90deg,#00ff9c,#00f0ff)",
      border: "none",
      borderRadius: 12,
      fontWeight: 700,
      cursor: "pointer",
      color: "#111",
      boxShadow: "0 5px 15px rgba(0,255,156,0.4)",
      transition: "0.3s all",
    },
    error: { color: "#ff3d00", marginTop: 10 },
  };

  const lightTheme = {
    page: { minHeight: "100vh", background: "#f9f9f9", fontFamily: "Poppins, sans-serif", padding: 30, color: "#111" },
    container: { maxWidth: 900, margin: "auto", padding: "0 15px" },
    header: { textAlign: "center", marginBottom: 50 },
    logo: { fontSize: 42, fontWeight: 800, color: "#2d3436" },
    tagline: { marginTop: 10, color: "#636e72", fontSize: 16 },
    uploadCard: { background: "#fff", padding: 30, borderRadius: 18, border: "1px solid #e0e0e0", boxShadow: "0 5px 15px rgba(0,0,0,0.05)", marginBottom: 40 },
    uploadLabel: { display: "block", border: "2px dashed #0984e3", padding: 25, borderRadius: 15, textAlign: "center", fontWeight: 600, cursor: "pointer", marginBottom: 25, color: "#2d3436", transition: "0.3s all" },
    preview: { width: "100%", maxHeight: 320, borderRadius: 15, marginBottom: 15, cursor: "zoom-in", objectFit: "cover", boxShadow: "0 0 15px rgba(0,0,0,0.1)", transition: "all 0.3s ease" },
    previewZoom: { width: "100%", maxHeight: 600, borderRadius: 15, marginBottom: 15, cursor: "zoom-out", objectFit: "contain", boxShadow: "0 0 25px rgba(0,0,0,0.15)", transition: "all 0.3s ease" },
    buttonRow: { display: "flex", gap: 15, justifyContent: "center", flexWrap: "wrap" },
    primaryBtn: { padding: "12px 28px", background: "#0984e3", borderRadius: 12, border: "none", fontWeight: 600, cursor: "pointer", color: "#fff", boxShadow: "0 5px 15px rgba(9,132,227,0.4)", transition: "0.3s all" },
    resetBtn: { padding: "12px 28px", background: "#d63031", borderRadius: 12, border: "none", fontWeight: 600, cursor: "pointer", color: "#fff", boxShadow: "0 5px 15px rgba(214,48,49,0.4)", transition: "0.3s all" },
    disabledBtn: { padding: "12px 28px", background: "#b2bec3", borderRadius: 12, border: "none", color: "#636e72", cursor: "not-allowed" },
    resultCard: { background: "#fff", borderRadius: 18, padding: 35, boxShadow: "0 10px 30px rgba(0,0,0,0.05)", marginTop: 20 },
    meta: { fontSize: 13, color: "#636e72" },
    stats: { display: "flex", flexWrap: "wrap", gap: 15, margin: "30px 0", justifyContent: "center" },
    statBox: { flex: "1 1 200px", padding: 20, borderRadius: 15, background: "#f1f3f6", textAlign: "center", boxShadow: "0 5px 15px rgba(0,0,0,0.05)", cursor: "default", transition: "0.3s transform" },
    gauge: { width: 90, height: 90 },
    gaugeText: { fontSize: 10, fontWeight: 700, fill: "#2d3436", textAnchor: "middle" },
    progressBar: { height: 14, background: "#dfe6e9", borderRadius: 12, overflow: "hidden", marginBottom: 20 },
    progressFill: { height: "100%", background: "linear-gradient(90deg,#00b894,#fdcb6e,#d63031)", transition: "width 1s ease" },
    partItem: { display: "flex", justifyContent: "space-between", padding: "10px 0", borderBottom: "1px solid #dfe6e9" },
    severity: { background: "#d6303133", color: "#d63031", padding: "3px 10px", borderRadius: 8, fontWeight: 600 },
    pre: { background: "#f1f3f6", padding: 20, borderRadius: 12, overflowX: "auto", color: "#2d3436" },
    downloadBtn: { marginTop: 25, padding: "12px 28px", background: "#0984e3", border: "none", borderRadius: 12, fontWeight: 700, cursor: "pointer", color: "#fff", boxShadow: "0 5px 15px rgba(9,132,227,0.4)", transition: "0.3s all" },
    error: { color: "#d63031", marginTop: 10 },
  };

  const theme = darkMode ? darkTheme : lightTheme;

  return (
    <div style={theme.page}>
      <div style={theme.container}>
        <header style={theme.header}>
          <h1 style={theme.logo}>ClaimPilot AI</h1>
          <p style={theme.tagline}>Automated Vehicle Damage Assessment & Fraud Detection</p>
        </header>

        <div style={theme.uploadCard}>
          <label style={theme.uploadLabel}>
            {file ? file.name : "Click or drag to upload a vehicle damage image"}
            <input type="file" onChange={handleFileChange} style={{ display: "none" }} />
          </label>

          {preview && (
            <img
              src={preview}
              alt="Preview"
              style={zoom ? theme.previewZoom : theme.preview}
              onClick={() => setZoom(!zoom)}
            />
          )}

          <div style={theme.buttonRow}>
            <button style={theme.primaryBtn} onClick={handleUpload} disabled={loading}>
              {loading ? "Analyzing..." : "Analyze Damage"}
            </button>
            <button style={theme.resetBtn} onClick={handleReset}>
              Reset
            </button>
            <button
              style={theme.downloadBtn}
              onClick={downloadReport}
              disabled={!result || downloading}
            >
              {downloading ? "Downloading..." : "Download Report"}
            </button>
          </div>

          {error && <p style={theme.error}>{error}</p>}
        </div>

        {result && (
          <div style={theme.resultCard}>
            <p style={theme.meta}>
              Claim ID: <strong>{claimId}</strong> | Date: {new Date().toLocaleString()}
            </p>

            <div style={theme.stats}>
              <div style={theme.statBox}>
                <h3>Total Estimate</h3>
                <p>PKR {result.total_estimate_pkr}</p>
              </div>
              <div style={theme.statBox}>
                <h3>Fraud Score</h3>
                <p style={{ color: gaugeColor(animatedScore), fontWeight: "700" }}>
                  {animatedScore}%
                </p>
                <p>{riskLevel(animatedScore)}</p>
              </div>
              <div style={theme.statBox}>
                <h3>Verdict</h3>
                <p style={{ color: verdictColor(result.verdict), fontWeight: "700" }}>
                  {result.verdict}
                </p>
              </div>
              <div style={theme.statBox}>
                <h3>Damaged Parts</h3>
                <p>{result.damaged_parts?.length || 0}</p>
              </div>
            </div>

            <h3>Damaged Parts:</h3>
            {result.damaged_parts?.length ? (
              result.damaged_parts.map((part, idx) => (
                <div key={idx} style={theme.partItem}>
                  <span>{part}</span>
                </div>
              ))
            ) : (
              <p>No parts detected</p>
            )}

            <h3>Itemized Costs:</h3>
            <pre style={theme.pre}>{JSON.stringify(result.itemized_costs, null, 2)}</pre>

            <h3>Fraud Analysis:</h3>
            <p>{result.fraud_analysis || "No fraud detected."}</p>
          </div>
        )}
      </div>
    </div>
  );
}

export default App;
